async function handleSearch(request: Request, env: Env, corsHeaders: any) {
    const url = new URL(request.url);
    const query = url.searchParams.get('q') || '';
    const searchPattern = `%${query}%`;
    
    const { results: users } = await env.DB.prepare('SELECT * FROM users WHERE name LIKE ? OR email LIKE ?').bind(searchPattern, searchPattern).all();
    
    // Enhanced release search to include UPC and ISRC
    const { results: releases } = await env.DB.prepare(`
        SELECT DISTINCT r.* 
        FROM releases r
        LEFT JOIN tracks t ON r.id = t.release_id
        WHERE r.title LIKE ? 
        OR r.upc LIKE ? 
        OR t.isrc LIKE ?
    `).bind(searchPattern, searchPattern, searchPattern).all();
    
    const { results: artists } = await env.DB.prepare('SELECT * FROM artists WHERE name LIKE ?').bind(searchPattern).all();
    const { results: labels } = await env.DB.prepare('SELECT * FROM labels WHERE name LIKE ?').bind(searchPattern).all();

    return new Response(JSON.stringify({
        users: (users || []).map(mapUser),
        releases: (releases || []).map(mapRelease),
        artists: (artists || []).map(mapArtist),
        labels: (labels || []).map(mapLabel)
    }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
}

async function handleStats(request: Request, env: Env, corsHeaders: any) {
    if (request.method === 'GET') {
        const url = new URL(request.url);
        const labelId = url.searchParams.get('labelId');

        let artistsQuery, labelsQuery, releasesQuery;
        const params: any[] = [];

        if (labelId) {
            params.push(labelId);
            artistsQuery = `
                WITH RECURSIVE sub_labels AS (
                    SELECT id FROM labels WHERE id = ?
                    UNION ALL
                    SELECT l.id FROM labels l JOIN sub_labels sl ON l.parent_label_id = sl.id
                )
                SELECT COUNT(*) as count FROM artists WHERE label_id IN (SELECT id FROM sub_labels)
            `;
            labelsQuery = `
                WITH RECURSIVE sub_labels AS (
                    SELECT id FROM labels WHERE id = ?
                    UNION ALL
                    SELECT l.id FROM labels l JOIN sub_labels sl ON l.parent_label_id = sl.id
                )
                SELECT COUNT(*) as count FROM labels WHERE parent_label_id IN (SELECT id FROM sub_labels)
            `;
            releasesQuery = `
                WITH RECURSIVE sub_labels AS (
                    SELECT id FROM labels WHERE id = ?
                    UNION ALL
                    SELECT l.id FROM labels l JOIN sub_labels sl ON l.parent_label_id = sl.id
                )
                SELECT 
                    COUNT(CASE WHEN status = 'Draft' THEN 1 END) as drafted,
                    COUNT(CASE WHEN status = 'Published' THEN 1 END) as published,
                    COUNT(CASE WHEN status = 'Rejected' THEN 1 END) as rejected,
                    COUNT(CASE WHEN status = 'Needs Info' THEN 1 END) as correction,
                    COUNT(CASE WHEN status = 'Takedown' THEN 1 END) as takedown,
                    COUNT(CASE WHEN status = 'Pending' THEN 1 END) as pending
                FROM releases
                WHERE label_id IN (SELECT id FROM sub_labels)
            `;
        } else {
            artistsQuery = 'SELECT COUNT(*) as count FROM artists';
            labelsQuery = 'SELECT COUNT(*) as count FROM labels';
            releasesQuery = `
                SELECT 
                    COUNT(CASE WHEN status = 'Draft' THEN 1 END) as drafted,
                    COUNT(CASE WHEN status = 'Published' THEN 1 END) as published,
                    COUNT(CASE WHEN status = 'Rejected' THEN 1 END) as rejected,
                    COUNT(CASE WHEN status = 'Needs Info' THEN 1 END) as correction,
                    COUNT(CASE WHEN status = 'Takedown' THEN 1 END) as takedown,
                    COUNT(CASE WHEN status = 'Pending' THEN 1 END) as pending
                FROM releases
            `;
        }

        const artists = await env.DB.prepare(artistsQuery).bind(...params).first() as any;
        const labels = await env.DB.prepare(labelsQuery).bind(...params).first() as any;
        const releaseStats = await env.DB.prepare(releasesQuery).bind(...params).first() as any;

        return new Response(JSON.stringify({
            artists: artists?.count || 0,
            labels: labels?.count || 0,
            drafted: releaseStats?.drafted || 0,
            published: releaseStats?.published || 0,
            rejected: releaseStats?.rejected || 0,
            correction: releaseStats?.correction || 0,
            takedown: releaseStats?.takedown || 0,
            pending: releaseStats?.pending || 0
        }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }
    return new Response(null, { status: 405, headers: corsHeaders });
}

